const plugin = createExtismSourcePlugin({
  name: 'my-source',
  version: '1.0.0',
  open(ctx) {
    ctx.log('Source opened');
  },
  read(ctx) {
    // Return null when exhausted
    return {
      operation: 'INSERT',
      data: { message: 'hello', ts: Date.now() },
      metadata: {
        source: 'my-source',
        timestamp: new Date().toISOString(),
      },
    };
  },
  close(ctx) {
    ctx.log('Source closed');
  },
});

